    "path": "baldurs-gate-3-trainer/Program.cs",
    "content": "using System;\nusing System.Threading;\nusing BaldursGate3Trainer.Core;\n\nnamespace BaldursGate3Trainer\n{\n    class Program\n    {\n        static void Main(string[] args)\n        {\n            Console.WriteLine(\"Baldur's Gate 3 Trainer v1.0\");\n            Console.WriteLine(\"===============================\");\n            Console.WriteLine(\"Features: God Mode, Max Stats, Infinite Items, Unlimited Actions\");\n            Console.WriteLine(\"Press F1 to toggle God Mode\");\n            Console.WriteLine(\"Press F2 to toggle Max Stats\");\n            Console.WriteLine(\"Press F3 to toggle Infinite Items\");\n            Console.WriteLine(\"Press F4 to toggle Unlimited Actions\");\n            Console.WriteLine(\"Press Escape to exit.\");\n\n            var trainer = new TrainerEngine();\n            trainer.Start();\n\n            while (true)\n            {\n                if (Console.KeyAvailable)\n                {\n                    var key = Console.ReadKey(true).Key;\n                    switch (key)\n                    {\n                        case ConsoleKey.F1:\n                            trainer.ToggleGodMode();\n                            Console.WriteLine($\"God Mode: {trainer.GodModeEnabled}\");\n                            break;\n                        case ConsoleKey.F2:\n                            trainer.ToggleMaxStats();\n                            Console.WriteLine($\"Max Stats: {trainer.MaxStatsEnabled}\");\n                            break;\n                        case ConsoleKey.F3:\n                            trainer.ToggleInfiniteItems();\n                            Console.WriteLine($\"Infinite Items: {trainer.InfiniteItemsEnabled}\");\n                            break;\n                        case ConsoleKey.F4:\n                            trainer.ToggleUnlimitedActions();\n                            Console.WriteLine($\"Unlimited Actions: {trainer.UnlimitedActionsEnabled}\");\n                            break;\n                        case ConsoleKey.Escape:\n                            trainer.Stop();\n                            Console.WriteLine(\"Trainer stopped.\");\n                            return;\n                    }\n                }\n                Thread.Sleep(50);\n            }\n        }\n    }\n}\n"
  },
