    "path": "baldurs-gate-3-trainer/Core/TrainerEngine.cs",
    "content": "using System;\nusing System.Diagnostics;\nusing System.Runtime.InteropServices;\nusing System.Threading;\n\nnamespace BaldursGate3Trainer.Core\n{\n    /// <summary>\n    /// Core engine for the Baldur's Gate 3 trainer.\n    /// Manages memory reading/writing and feature toggles.\n    /// </summary>\n    public class TrainerEngine\n    {\n        // Windows API imports for process memory manipulation\n        [DllImport(\"kernel32.dll\")]\n        private static extern IntPtr OpenProcess(uint dwDesiredAccess, bool bInheritHandle, int dwProcessId);\n\n        [DllImport(\"kernel32.dll\")]\n        private static extern bool ReadProcessMemory(IntPtr hProcess, IntPtr lpBaseAddress, byte[] lpBuffer, int dwSize, out int lpNumberOfBytesRead);\n\n        [DllImport(\"kernel32.dll\")]\n        private static extern bool WriteProcessMemory(IntPtr hProcess, IntPtr lpBaseAddress, byte[] lpBuffer, int dwSize, out int lpNumberOfBytesWritten);\n\n        [DllImport(\"kernel32.dll\")]\n        private static extern bool CloseHandle(IntPtr hObject);\n\n        private const uint PROCESS_ALL_ACCESS = 0x1F0FFF;\n\n        private IntPtr _processHandle;\n        private Process _targetProcess;\n        private Thread _monitorThread;\n        private bool _isRunning;\n        private bool _disposed;\n\n        // Feature states\n        public bool GodModeEnabled { get; private set; }\n        public bool MaxStatsEnabled { get; private set; }\n        public bool InfiniteItemsEnabled { get; private set; }\n        public bool UnlimitedActionsEnabled { get; private set; }\n\n        // Memory offsets (example values, would need real offsets from reverse engineering)\n        private const int GodModeOffset = 0x00A1B2C3;\n        private const int MaxStatsOffset = 0x00A1B2C7;\n        private const int InfiniteItemsOffset = 0x00A1B2CB;\n        private const int UnlimitedActionsOffset = 0x00A1B2CF;\n\n        /// <summary>\n        /// Initializes a new instance of the TrainerEngine.\n        /// </summary>\n        public TrainerEngine()\n        {\n            FindTargetProcess();\n        }\n\n        /// <summary>\n        /// Finds the Baldur's Gate 3 process by name.\n        /// </summary>\n        private void FindTargetProcess()\n        {\n            var processes = Process.GetProcessesByName(\"bg3\");\n            if (processes.Length == 0)\n            {\n                throw new InvalidOperationException(\"Baldur's Gate 3 process not found. Please start the game first.\");\n            }\n            _targetProcess = processes[0];\n            _processHandle = OpenProcess(PROCESS_ALL_ACCESS, false, _targetProcess.Id);\n            if (_processHandle == IntPtr.Zero)\n            {\n                throw new InvalidOperationException(\"Failed to open process handle. Try running as administrator.\");\n            }\n        }\n\n        /// <summary>\n        /// Starts the trainer monitoring loop.\n        /// </summary>\n        public void Start()\n        {\n            if (_isRunning) return;\n            _isRunning = true;\n            _monitorThread = new Thread(MonitorLoop)\n            {\n                IsBackground = true,\n                Name = \"TrainerMonitorThread\"\n            };\n            _monitorThread.Start();\n        }\n\n        /// <summary>\n        /// Stops the trainer monitoring loop and cleans up.\n        /// </summary>\n        public void Stop()\n        {\n            _isRunning = false;\n            _monitorThread?.Join(1000);\n            Dispose();\n        }\n\n        /// <summary>\n        /// Main monitoring loop that applies trainer features each cycle.\n        /// </summary>\n        private void MonitorLoop()\n        {\n            while (_isRunning)\n            {\n                if (GodModeEnabled)\n                    WriteMemory(GodModeOffset, new byte[] { 0x01 }); // Set god mode flag to 1\n                if (MaxStatsEnabled)\n                    WriteMemory(MaxStatsOffset, new byte[] { 0xFF }); // Set max stats (255)\n                if (InfiniteItemsEnabled)\n                    WriteMemory(InfiniteItemsOffset, new byte[] { 0x63 }); // Set items to 99\n                if (UnlimitedActionsEnabled)\n                    WriteMemory(UnlimitedActionsOffset, new byte[] { 0x01 }); // Enable unlimited actions\n\n                Thread.Sleep(100); // Check every 100ms\n            }\n        }\n\n        /// <summary>\n        /// Writes bytes to the target process memory at a given offset from base address.\n        /// </summary>\n        private void WriteMemory(int offset, byte[] data)\n        {\n            if (_processHandle == IntPtr.Zero) return;\n            IntPtr address = _targetProcess.MainModule.BaseAddress + offset;\n            WriteProcessMemory(_processHandle, address, data, data.Length, out _);\n        }\n\n        /// <summary>\n        /// Reads bytes from the target process memory at a given offset.\n        /// </summary>\n        private byte[] ReadMemory(int offset, int size)\n        {\n            if (_processHandle == IntPtr.Zero) return null;\n            IntPtr address = _targetProcess.MainModule.BaseAddress + offset;\n            byte[] buffer = new byte[size];\n            ReadProcessMemory(_processHandle, address, buffer, size, out _);\n            return buffer;\n        }\n\n        // Toggle methods\n        public void ToggleGodMode() => GodModeEnabled = !GodModeEnabled;\n        public void ToggleMaxStats() => MaxStatsEnabled = !MaxStatsEnabled;\n        public void ToggleInfiniteItems() => InfiniteItemsEnabled = !InfiniteItemsEnabled;\n        public void ToggleUnlimitedActions() => UnlimitedActionsEnabled = !UnlimitedActionsEnabled;\n\n        /// <summary>\n        /// Disposes resources used by the trainer.\n        /// </summary>\n        public void Dispose()\n        {\n            if (_disposed) return;\n            if (_processHandle != IntPtr.Zero)\n            {\n                CloseHandle(_processHandle);\n                _processHandle = IntPtr.Zero;\n            }\n            _disposed = true;\n            GC.SuppressFinalize(this);\n        }\n\n        ~TrainerEngine()\n        {\n            Dispose();\n        }\n    }\n}\n"
  },
