    "path": "baldurs-gate-3-trainer/Core/MemoryManager.cs",
    "content": "using System;\nusing System.Collections.Generic;\nusing System.Diagnostics;\nusing System.Runtime.InteropServices;\n\nnamespace BaldursGate3Trainer.Core\n{\n    /// <summary>\n    /// Provides low-level memory operations for the Baldur's Gate 3 process.\n    /// Handles scanning for patterns and reading/writing memory regions.\n    /// </summary>\n    public class MemoryManager : IDisposable\n    {\n        [DllImport(\"kernel32.dll\")]\n        private static extern bool VirtualProtectEx(IntPtr hProcess, IntPtr lpAddress, int dwSize, uint flNewProtect, out uint lpflOldProtect);\n\n        private readonly IntPtr _processHandle;\n        private readonly Process _targetProcess;\n        private bool _disposed;\n\n        /// <summary>\n        /// Initializes a new instance of MemoryManager.\n        /// </summary>\n        /// <param name=\"processHandle\">Handle to the target process.</param>\n        /// <param name=\"targetProcess\">The target process object.</param>\n        public MemoryManager(IntPtr processHandle, Process targetProcess)\n        {\n            _processHandle = processHandle;\n            _targetProcess = targetProcess;\n        }\n\n        /// <summary>\n        /// Scans the process memory for a specific byte pattern.\n        /// </summary>\n        /// <param name=\"pattern\">Byte pattern to search for.</param>\n        /// <param name=\"mask\">Mask string ('x' for match, '?' for wildcard).</param>\n        /// <returns>List of addresses where the pattern was found.</returns>\n        public List<IntPtr> ScanPattern(byte[] pattern, string mask)\n        {\n            var results = new List<IntPtr>();\n            IntPtr baseAddress = _targetProcess.MainModule.BaseAddress;\n            int moduleSize = _targetProcess.MainModule.ModuleMemorySize;\n\n            for (int i = 0; i < moduleSize - pattern.Length; i++)\n            {\n                bool found = true;\n                for (int j = 0; j < pattern.Length; j++)\n                {\n                    if (mask[j] == 'x' && pattern[j] != ReadByte(baseAddress + i + j))\n                    {\n                        found = false;\n                        break;\n                    }\n                }\n                if (found)\n                {\n                    results.Add(baseAddress + i);\n                }\n            }\n            return results;\n        }\n\n        /// <summary>\n        /// Reads a single byte from the target process memory.\n        /// </summary>\n        private byte ReadByte(IntPtr address)\n        {\n            byte[] buffer = new byte[1];\n            NativeMethods.ReadProcessMemory(_processHandle, address, buffer, 1, out _);\n            return buffer[0];\n        }\n\n        /// <summary>\n        /// Changes memory protection to allow writing.\n        /// </summary>\n        public bool UnprotectMemory(IntPtr address, int size)\n        {\n            return VirtualProtectEx(_processHandle, address, size, 0x40, out _); // PAGE_EXECUTE_READWRITE\n        }\n\n        /// <summary>\n        /// Writes a byte array to a specific address.\n        /// </summary>\n        public bool WriteBytes(IntPtr address, byte[] data)\n        {\n            if (!UnprotectMemory(address, data.Length))\n                return false;\n            return NativeMethods.WriteProcessMemory(_processHandle, address, data, data.Length, out _);\n        }\n\n        /// <summary>\n        /// Reads a byte array from a specific address.\n        /// </summary>\n        public byte[] ReadBytes(IntPtr address, int size)\n        {\n            byte[] buffer = new byte[size];\n            NativeMethods.ReadProcessMemory(_processHandle, address, buffer, size, out _);\n            return buffer;\n        }\n\n        public void Dispose()\n        {\n            if (_disposed) return;\n            _disposed = true;\n            GC.SuppressFinalize(this);\n        }\n    }\n\n    /// <summary>\n    /// Internal class for P/Invoke declarations.\n    /// </summary>\n    internal static class NativeMethods\n    {\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        internal static extern bool ReadProcessMemory(IntPtr hProcess, IntPtr lpBaseAddress, byte[] lpBuffer, int dwSize, out int lpNumberOfBytesRead);\n\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        internal static extern bool WriteProcessMemory(IntPtr hProcess, IntPtr lpBaseAddress, byte[] lpBuffer, int dwSize, out int lpNumberOfBytesWritten);\n    }\n}\n"
  },
