    "path": "baldurs-gate-3-trainer/Core/FeatureManager.cs",
    "content": "using System;\nusing System.Collections.Generic;\n\nnamespace BaldursGate3Trainer.Core\n{\n    /// <summary>\n    /// Manages the state and configuration of trainer features.\n    /// Provides a high-level interface for toggling and querying features.\n    /// </summary>\n    public class FeatureManager\n    {\n        private readonly Dictionary<string, bool> _features;\n\n        /// <summary>\n        /// Initializes a new instance of FeatureManager with default disabled states.\n        /// </summary>\n        public FeatureManager()\n        {\n            _features = new Dictionary<string, bool>\n            {\n                { \"GodMode\", false },\n                { \"MaxStats\", false },\n                { \"InfiniteItems\", false },\n                { \"UnlimitedActions\", false },\n                { \"NoCooldown\", false },\n                { \"UnlimitedSpellSlots\", false }\n            };\n        }\n\n        /// <summary>\n        /// Toggles a feature by name.\n        /// </summary>\n        /// <param name=\"featureName\">The name of the feature (case-insensitive).</param>\n        /// <returns>True if the feature was found and toggled, false otherwise.</returns>\n        public bool ToggleFeature(string featureName)\n        {\n            if (_features.ContainsKey(featureName))\n            {\n                _features[featureName] = !_features[featureName];\n                Console.WriteLine($\"Feature '{featureName}' is now {(_features[featureName] ? \"enabled\" : \"disabled\")}.\");\n                return true;\n            }\n            Console.WriteLine($\"Feature '{featureName}' not recognized.\");\n            return false;\n        }\n\n        /// <summary>\n        /// Gets the current state of a feature.\n        /// </summary>\n        public bool IsFeatureEnabled(string featureName)\n        {\n            return _features.ContainsKey(featureName) && _features[featureName];\n        }\n\n        /// <summary>\n        /// Enables a specific feature.\n        /// </summary>\n        public void EnableFeature(string featureName)\n        {\n            if (_features.ContainsKey(featureName))\n                _features[featureName] = true;\n        }\n\n        /// <summary>\n        /// Disables a specific feature.\n        /// </summary>\n        public void DisableFeature(string featureName)\n        {\n            if (_features.ContainsKey(featureName))\n                _features[featureName] = false;\n        }\n\n        /// <summary>\n        /// Returns a list of all available features and their states.\n        /// </summary>\n        public Dictionary<string, bool> GetAllFeatures()\n        {\n            return new Dictionary<string, bool>(_features);\n        }\n\n        /// <summary>\n        /// Resets all features to disabled.\n        /// </summary>\n        public void ResetAllFeatures()\n        {\n            foreach (var key in _features.Keys)\n            {\n                _features[key] = false;\n            }\n            Console.WriteLine(\"All features have been reset to disabled.\");\n        }\n    }\n}\n"
  },
