    "path": "baldurs-gate-3-trainer/Tests/TrainerEngineTests.cs",
    "content": "using System;\nusing BaldursGate3Trainer.Core;\nusing Xunit;\n\nnamespace BaldursGate3Trainer.Tests\n{\n    /// <summary>\n    /// Unit tests for the TrainerEngine class.\n    /// Note: These tests do not require the actual game to be running.\n    /// </summary>\n    public class TrainerEngineTests\n    {\n        [Fact]\n        public void ToggleGodMode_ShouldToggleState()\n        {\n            // Arrange\n            var engine = new TrainerEngine();\n            bool initialState = engine.GodModeEnabled;\n\n            // Act\n            engine.ToggleGodMode();\n\n            // Assert\n
